#include <iostream>
using namespace std;

class BankAccount {
private:
    double balance;   // hidden from outside
public:
    string owner;

    void deposit(double amount) {
        if (amount > 0) balance += amount;
    }

    double getBalance() {
        return balance;
    }
};

int main() {
    BankAccount acc;
    acc.owner = "John";
    // acc.balance = 1000; // ERROR: private
    acc.deposit(500);
    cout << "Balance: " << acc.getBalance() << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Point {
public:
    int x, y;

    // Default constructor
    Point() {
        x = 0; y = 0;
        cout << "Default constructor" << endl;
    }

    // Parameterized constructor
    Point(int a, int b) {
        x = a; y = b;
        cout << "Parameterized constructor" << endl;
    }

    // Constructor with default arguments
    Point(int a) : x(a), y(a) {
        cout << "Constructor with default" << endl;
    }

    void display() {
        cout << "(" << x << "," << y << ")" << endl;
    }
};

int main() {
    Point p1;        // default
    Point p2(3, 4);  // parameterized
    Point p3(5);     // constructor with default
    p1.display();
    p2.display();
    p3.display();
    return 0;
}

#include <iostream>
using namespace std;

class Person {
private:
    const int id;    // const must be initialized in list
    string name;
    int& ageRef;     // reference must be initialized
public:
    Person(int i, string n, int& a) : id(i), name(n), ageRef(a) {
        cout << "Constructor body" << endl;
    }
    void display() {
        cout << "ID: " << id << ", Name: " << name << ", AgeRef: " << ageRef << endl;
    }
};

int main() {
    int age = 25;
    Person p(101, "Alice", age);
    p.display();
    return 0;
}

#include <iostream>
using namespace std;

class Resource {
public:
    Resource() {
        cout << "Resource acquired" << endl;
    }
    ~Resource() {
        cout << "Resource released" << endl;
    }
    void use() {
        cout << "Using resource" << endl;
    }
};

int main() {
    {
        Resource r;
        r.use();
    } // r destroyed here, destructor called
    cout << "After block" << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Box {
private:
    int length;
public:
    Box(int length) {
        this->length = length;  // this resolves name conflict
    }
    Box& setLength(int len) {
        this->length = len;
        return *this;   // return reference to current object for chaining
    }
    void display() {
        cout << "Length: " << this->length << endl;
    }
};

int main() {
    Box b(10);
    b.display();
    b.setLength(20).setLength(30).display(); // chaining
    return 0;
}

#include <iostream>
using namespace std;

class Counter {
private:
    static int count;   // static member declaration
    int id;
public:
    Counter() {
        id = ++count;
    }
    static int getCount() {   // static function
        return count;
    }
    void showId() {
        cout << "Object ID: " << id << endl;
    }
};

// Definition and initialization of static member
int Counter::count = 0;

int main() {
    Counter c1, c2, c3;
    c1.showId();
    c2.showId();
    c3.showId();
    cout << "Total objects: " << Counter::getCount() << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Data {
private:
    int value;
public:
    Data(int v) : value(v) {}
    int getValue() const {   // const member function
        // value = 10; // ERROR: cannot modify
        return value;
    }
    void setValue(int v) {
        value = v;
    }
};

int main() {
    const Data d1(42);   // const object
    cout << d1.getValue() << endl;
    // d1.setValue(99);  // ERROR: cannot call non-const on const object

    Data d2(100);
    d2.setValue(200);
    cout << d2.getValue() << endl;
    return 0;
}
